/**
 * Sample JavaScript file demonstrating object methods and function assignments
 * This file tests methods defined in object literals and prototype assignments
 */

// Object with method definitions
const calculator = {
    result: 0,

    // Method shorthand syntax
    add(value) {
        this.result += value;
        return this;
    },

    // Method shorthand syntax with parameters
    subtract(value) {
        this.result -= value;
        return this;
    },

    // Traditional method definition
    multiply: function(value) {
        this.result *= value;
        return this;
    },

    // Arrow function as method (note: 'this' behaves differently)
    reset: () => {
        // Note: Arrow functions don't have their own 'this'
        console.log('Calculator reset');
    },

    // Method with complex logic
    calculate(operation, value) {
        switch (operation) {
            case 'add':
                return this.add(value);
            case 'subtract':
                return this.subtract(value);
            case 'multiply':
                return this.multiply(value);
            default:
                throw new Error('Unknown operation');
        }
    },

    // Getter method
    get value() {
        return this.result;
    },

    // Setter method
    set value(newValue) {
        this.result = newValue;
    }
};

// Object with nested methods
const api = {
    baseUrl: 'https://api.example.com',

    users: {
        // Nested method
        getAll() {
            return fetch(`${this.baseUrl}/users`);
        },

        // Nested method with parameters
        getById(id) {
            return fetch(`${this.baseUrl}/users/${id}`);
        },

        // Async nested method
        async create(userData) {
            const response = await fetch(`${this.baseUrl}/users`, {
                method: 'POST',
                body: JSON.stringify(userData)
            });
            return response.json();
        }
    },

    posts: {
        getAll() {
            return fetch(`${this.baseUrl}/posts`);
        },

        getByUserId(userId) {
            return fetch(`${this.baseUrl}/posts?userId=${userId}`);
        }
    }
};

// Constructor function with prototype methods
function Vehicle(make, model, year) {
    this.make = make;
    this.model = model;
    this.year = year;
}

// Prototype method assignment
Vehicle.prototype.getInfo = function() {
    return `${this.year} ${this.make} ${this.model}`;
};

// Another prototype method
Vehicle.prototype.start = function() {
    console.log(`Starting ${this.getInfo()}`);
};

// Prototype method with parameters
Vehicle.prototype.drive = function(distance) {
    console.log(`Driving ${this.getInfo()} for ${distance} miles`);
};

// Static method assignment to constructor function
Vehicle.createElectric = function(make, model, year, batteryCapacity) {
    const vehicle = new Vehicle(make, model, year);
    vehicle.batteryCapacity = batteryCapacity;
    vehicle.charge = function(percentage) {
        console.log(`Charging to ${percentage}%`);
    };
    return vehicle;
};

// Object with methods that call other methods
const gameEngine = {
    score: 0,
    level: 1,

    // Method that calls other methods
    startGame() {
        this.initializeLevel();
        this.resetScore();
        this.showWelcomeMessage();
    },

    initializeLevel() {
        console.log(`Initializing level ${this.level}`);
    },

    resetScore() {
        this.score = 0;
        console.log('Score reset to 0');
    },

    showWelcomeMessage() {
        console.log('Welcome to the game!');
    },

    // Method with callback parameter
    processInput(input, callback) {
        console.log(`Processing input: ${input}`);
        if (callback && typeof callback === 'function') {
            callback(input);
        }
    },

    // Method that returns a function
    createScoreHandler() {
        return (points) => {
            this.score += points;
            console.log(`Score: ${this.score}`);
        };
    }
};

// Module pattern with private and public methods
const counterModule = (function() {
    let count = 0;

    // Private function
    function validateIncrement(value) {
        return typeof value === 'number' && value > 0;
    }

    // Return public interface
    return {
        // Public method
        increment(value = 1) {
            if (validateIncrement(value)) {
                count += value;
            }
        },

        // Public method
        decrement(value = 1) {
            if (validateIncrement(value)) {
                count -= value;
            }
        },

        // Public getter
        getCount() {
            return count;
        },

        // Public method that uses private function
        reset() {
            count = 0;
            console.log('Counter reset');
        }
    };
})();

// Factory function that creates objects with methods
function createTimer(name) {
    let startTime = null;
    let endTime = null;

    return {
        name: name,

        start() {
            startTime = Date.now();
            console.log(`Timer ${this.name} started`);
        },

        stop() {
            endTime = Date.now();
            console.log(`Timer ${this.name} stopped`);
        },

        getElapsed() {
            if (startTime && endTime) {
                return endTime - startTime;
            }
            return 0;
        },

        reset() {
            startTime = null;
            endTime = null;
            console.log(`Timer ${this.name} reset`);
        }
    };
}

// Function that demonstrates object method usage
function demonstrateObjects() {
    // Use calculator
    calculator.add(10).multiply(2).subtract(5);
    console.log('Calculator result:', calculator.value);

    // Use vehicle
    const car = new Vehicle('Toyota', 'Camry', 2022);
    car.start();
    car.drive(100);

    // Use game engine
    gameEngine.startGame();
    const scoreHandler = gameEngine.createScoreHandler();
    scoreHandler(100);

    // Use counter module
    counterModule.increment(5);
    counterModule.decrement(2);
    console.log('Counter value:', counterModule.getCount());

    // Use timer factory
    const timer = createTimer('TestTimer');
    timer.start();
    setTimeout(() => {
        timer.stop();
        console.log('Elapsed time:', timer.getElapsed());
    }, 1000);

    return {
        calculator,
        car,
        gameEngine,
        counterModule,
        timer
    };
}

// Export objects and functions
export { calculator, api, Vehicle, gameEngine, counterModule, createTimer };
export default demonstrateObjects;

/**
 * Sample JavaScript file demonstrating class definitions and methods
 * This file tests class declarations, methods, static methods, and inheritance
 */

// Basic class declaration
class Person {
    constructor(name, age) {
        this.name = name;
        this.age = age;
    }

    // Instance method
    greet() {
        return `Hello, I'm ${this.name} and I'm ${this.age} years old`;
    }

    /**
     * Method with JSDoc documentation
     * @param {number} years - Number of years to add
     * @returns {void}
     */
    celebrateBirthday(years = 1) {
        this.age += years;
        console.log(`Happy birthday! Now ${this.age} years old`);
    }

    // Getter method
    get info() {
        return `${this.name} (${this.age})`;
    }

    // Setter method
    set info(value) {
        const [name, age] = value.split(' ');
        this.name = name;
        this.age = parseInt(age);
    }

    // Static method
    static createAdult(name) {
        return new Person(name, 18);
    }

    // Static method with parameters
    static compare(person1, person2) {
        return person1.age - person2.age;
    }
}

// Class inheritance
class Employee extends Person {
    constructor(name, age, jobTitle, salary) {
        super(name, age);
        this.jobTitle = jobTitle;
        this.salary = salary;
    }

    // Override parent method
    greet() {
        return `${super.greet()}. I work as a ${this.jobTitle}`;
    }

    // New method specific to Employee
    work() {
        console.log(`${this.name} is working as a ${this.jobTitle}`);
    }

    // Method with complex parameters
    updateSalary(newSalary, reason = 'performance review') {
        const oldSalary = this.salary;
        this.salary = newSalary;
        console.log(`Salary updated from ${oldSalary} to ${newSalary} due to ${reason}`);
    }

    // Static method in child class
    static createIntern(name, age) {
        return new Employee(name, age, 'Intern', 0);
    }
}

// Class with private fields (modern JavaScript)
class BankAccount {
    #balance = 0;
    #accountNumber;

    constructor(accountNumber, initialBalance = 0) {
        this.#accountNumber = accountNumber;
        this.#balance = initialBalance;
    }

    // Public method accessing private field
    deposit(amount) {
        if (amount > 0) {
            this.#balance += amount;
            return this.#balance;
        }
        throw new Error('Amount must be positive');
    }

    // Public method accessing private field
    withdraw(amount) {
        if (amount > 0 && amount <= this.#balance) {
            this.#balance -= amount;
            return this.#balance;
        }
        throw new Error('Invalid withdrawal amount');
    }

    // Getter for private field
    get balance() {
        return this.#balance;
    }

    // Private method
    #validateTransaction(amount) {
        return amount > 0 && amount <= this.#balance;
    }
}

// Class with static properties and methods
class MathUtils {
    static PI = 3.14159;
    static E = 2.71828;

    static add(a, b) {
        return a + b;
    }

    static multiply(a, b) {
        return a * b;
    }

    static circleArea(radius) {
        return MathUtils.PI * radius * radius;
    }
}

// Class expression assigned to variable
const AnonymousClass = class {
    constructor(value) {
        this.value = value;
    }

    getValue() {
        return this.value;
    }
};

// Mixin pattern using classes
const Flyable = (Base) => class extends Base {
    fly() {
        console.log(`${this.name} is flying!`);
    }
};

const Swimmable = (Base) => class extends Base {
    swim() {
        console.log(`${this.name} is swimming!`);
    }
};

// Class using mixins
class Duck extends Swimmable(Flyable(Person)) {
    constructor(name) {
        super(name, 0); // Ducks don't have human age
        this.species = 'Duck';
    }

    quack() {
        console.log(`${this.name} says: Quack!`);
    }
}

// Function that creates and uses class instances
function demonstrateClasses() {
    const person = new Person('Alice', 30);
    const employee = new Employee('Bob', 25, 'Developer', 75000);
    const account = new BankAccount('12345', 1000);
    const duck = new Duck('Donald');

    // Call various methods
    console.log(person.greet());
    console.log(employee.greet());
    employee.work();

    account.deposit(500);
    console.log('Balance:', account.balance);

    duck.quack();
    duck.fly();
    duck.swim();

    return {
        person,
        employee,
        account,
        duck
    };
}

// Export classes
export { Person, Employee, BankAccount, MathUtils, Duck };
export default demonstrateClasses;

